onClick:
{{
!inpClaveAnulacionFactura.text

?

showAlert(
    "Debe indicar la clave de anulación",
    "warning"
)

:

!inpRazonAnulacionFactura.text.trim()

?

showAlert(
    "Debe indicar la razón de anulación",
    "warning"
)

:

qryFCAnular.run(

    () => {

        showAlert(
            "Factura anulada correctamente",
            "success"
        );

        closeModal(
            "mdlAnularFactura"
        );

        resetWidget(
            "inpClaveAnulacionFactura"
        );

        resetWidget(
            "inpRazonAnulacionFactura"
        );

        BuscarFC.run();

    }

)
}}
